var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그쪽은 어때? 사람 그림자라도 보여?","JPN":"そっちはどう？　人影でも見える？","ENG":"How about over there? Do you see even a single person?","TWN":"那邊怎麼樣？看到人影了嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"...제 눈에도 보이지 않사옵니다.","JPN":"……わたくしにも見えません。","ENG":"...I can't see anyone either.","TWN":"……我沒看到。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"이렇게 아침 일찍 이곳에 와본 것은 처음이라...","JPN":"こんな朝早くにここに来たのは初めてなので……","ENG":"It is my first time coming here this early in the morning...","TWN":"我還是第一次這麼早來到這裡……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"힉-","JPN":"ひっ……","ENG":"Eek–","TWN":"咿—"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"왜 그래?","JPN":"どうしたの？","ENG":"What is it?","TWN":"怎麼了？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"저기에, 새까만 것이 툭 떨어졌사온데...","JPN":"あそこに、真っ黒なものが落ちたのですが……","ENG":"Something pitch-black just fell over there...","TWN":"那邊剛才有個黑色的東西掉下來……"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이건... 나뭇가지네.","JPN":"これは……木の枝だね。","ENG":"This is... just a tree branch.","TWN":"這是……樹枝。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"나뭇가지?","JPN":"木の枝？","ENG":"A tree branch?","TWN":"樹枝？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그리고 절단면이 반듯해. 누가 일부러 자른 것처럼.","JPN":"切断面がきれいだ。まるで誰かがわざと切ったように。","ENG":"And the cut is clean. Like someone cut it on purpose.","TWN":"而且切口很整齊，看起來像被人刻意砍下來的。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그렇다는 건...?","JPN":"ということは……？","ENG":"Which means...?","TWN":"那表示……？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"죄송해요. 혹시 떨어진 가지에 맞으셨나요?","JPN":"すみません。もしかして落ちた枝に当たりました？","ENG":"I'm sorry. Did a falling branch hit you?","TWN":"不好意思，你們有被掉下來的樹枝砸到嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"왜 나무를 타고 있는 거야?","JPN":"なんで木登りなんてしてるわけ？","ENG":"Why are you climbing a tree?","TWN":"你為什麼會爬到樹上？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"전 아침이 되면 가지를 치러 이곳에 나오거든요.","JPN":"私は朝になるとここに剪定に来るんです。","ENG":"Every morning, I come out here to trim the branches.","TWN":"我每天早上都會來這裡修剪樹枝。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"가지를 치고 있었다고?","JPN":"剪定？","ENG":"You were trimming branches?","TWN":"修剪樹枝？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"어차피 하루가 지나면 다시 돌아올 텐데, 그런 짓에 무슨 의미가 있지?","JPN":"どうせ一日が過ぎたらまた元通りになるのに、剪定する意味があるの？","ENG":"They'll just grow back tomorrow anyway. What's the point of doing something like that?","TWN":"反正過一天又會長回來，做這種事有什麼意義？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"확인해보고 싶어서요.","JPN":"確認してみたくて。","ENG":"Because I wanted to see.","TWN":"因為我想確認。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"어떤 가지를 자르고 어떤 가지를 남겨야, 나무그늘 아래의 햇살이 가장 아름답게 반짝이는지를.","JPN":"どんな枝を切ってどんな枝を残せば、木漏れ日が一番綺麗に輝くのかを。","ENG":"Which branches I should cut and which I should leave for the sunlight beneath the tree to sparkle most beautifully.","TWN":"到底要剪掉哪些樹枝、留下哪些樹枝，才能讓樹蔭下的陽光閃耀得最美。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"허.","JPN":"は。","ENG":"Huh.","TWN":"呵。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"죽은 사람도 살려내는 이 대단한 낙원에서 무슨 음모를 꾸미나 했더니, 매일 그런 시시한 놀이나 하고 있었다고?","JPN":"死んだ人も蘇らせるこの立派な楽園で何を企んでいるのかと思ったら、毎日そんなくだらない遊びをしてたの？","ENG":"So in this grand paradise that can even bring the dead back to life, I wondered what kind of scheme you were plotting... and it turns out you've just been playing trivial games like that every day?","TWN":"我還以為你在這個連死人都能復活的了不起樂園裡策劃著什麼陰謀，結果每天只是做這種無聊事？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"후후, 시시한가요?","JPN":"ふふ、くだらないですか？","ENG":"Haha, is it trivial?","TWN":"呵呵，很無聊嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그치만 저에게 나뭇가지를 자르는 건, 이제 일상인 걸요.","JPN":"ですが私にとって木の枝を切ることは、もはや日常なんです。","ENG":"But trimming branches has become part of my daily life now.","TWN":"不過對我來說，修剪樹枝已經是日常生活了。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"가장 완벽한 정오의 햇살을 눈에 담는 건 간단한 일이 아니니까요.","JPN":"一番完璧な正午の日差しを目にすることは、そう簡単なことではないですから。","ENG":"Capturing the most perfect midday sunlight is not such a simple thing.","TWN":"因為要把最完美的正午陽光收入眼中，可不是一件簡單的事。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"...아우드라.","JPN":"……アウドラ。","ENG":"...Audra.","TWN":"……奧德拉。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"이 낙원을 만든 것이 그대입니까?","JPN":"この楽園を作ったのは、あなたなのですか？","ENG":"Was it really you who created this Promised Land?","TWN":"這個樂園，是你創造的嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"네.","JPN":"はい。","ENG":"Yes.","TWN":"是。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"제가 엘리시온으로 오기 전에 살았던 고향의 풍경을 본 따 만들었어요.","JPN":"私がエリシオンに来る前に住んでいた故郷の風景を真似て作りました。","ENG":"I modeled it after the scenery of my hometown, where I lived before coming to Elysion.","TWN":"我按照自己來到艾利森前，曾住過的故鄉景色打造的。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"아발론 몰락 이후에 세워진, 아나필리스라는 나라였죠.","JPN":"アバロンが没落した後に建てられた、アナピリスという国でした。","ENG":"It was a country called Anapilis, founded after the fall of Avalon.","TWN":"那是阿瓦隆滅亡後建立的國家，叫阿納菲莉絲。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"아나필리스...?","JPN":"アナピリス……？","ENG":"Anapilis...?","TWN":"阿納菲莉絲……？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"에클리시아, 거기가 어딘지 알고 있어?","JPN":"エクレシア、知ってるの？","ENG":"Ecclesia, do you know where that is?","TWN":"艾可露西亞，你知道那是哪裡嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"...그곳에 대한 이야긴, 잘은 모릅니다.","JPN":"……その国についての詳しいことは存じません。","ENG":"...I don't know much about that place.","TWN":"……我完全不知道那個地方的事。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"다만 엘리시온에선... 아나필리스라는 이국에서 온 신앙인들을 이교도라며 핍박했었지요.","JPN":"ただエリシオンでは……アナピリスという異国から来た信者たちを、異教徒だと迫害したのです。","ENG":"But in Elysion... believers who came from a foreign land called Anapilis were persecuted as heretics.","TWN":"不過在艾利森……來自阿納菲莉絲的信徒被視為異教徒而遭受迫害。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};